INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06540', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '每個研究都有一個或一個以上的研究目的，而研究目的會影響研究設計的決定，下列有關研究目的 與研究設計的敘述何者錯誤？ 不論那一種研究目的，質化、量化或合併兩者的研究方法均可採用 評估性研究的目的僅包括描述與解釋 探索性研究的主要限制在於無論採用何種研究方法，它們不易得到研究問題的具決定性答案 量化描述性研究最主要的考量是資料描述的客觀性、精準性與可通則性', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06541', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關典範（paradigm）的敘述，何者錯誤？ 典範是形塑我們對這個世界觀察與理解的基本模型或參考架構 實證主義典範強調在觀察與理解事實的探索過程中追求客觀性 社會建構典範強調觀察無法完全客觀而需採納多元的主觀性 在社會科學裡，典範的轉移或典範的被取代，是指科學由對的觀點取代錯誤的觀點', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06542', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者不是集中趨勢測量？ 標準差  平均數  中位數  眾數', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06543', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者在進行文獻探討時，常會使用圖書館的館藏圖書、資料庫或利用網路線上查詢相關文獻，一 般線上搜尋有不同的搜尋方式，如輸入作者、書名、關鍵字等，為了提升搜尋的效率，我們會利用 「布林代數」的字「AND」、「OR」、「NOT」來連結我們搜尋的主題或關鍵字。下列敘述何 者錯誤？ 如果你希望快速找「少數民族孩童目睹家庭暴力」相關文獻，你可輸入「少數民族 OR孩童 OR 家 庭暴力」 如果你不希望含有某一特殊字詞的文獻出現在你的搜尋裡面，你可以用NOT放在你不希望出現的 關鍵字前 如果你希望縮小找尋的範圍通常可以用AND將你希望查詢的關鍵字連結起來 如果你將「少數民族目睹家庭暴力的有效處遇」這句話完整一字不差的當關鍵字搜尋，搜尋結果 系統回應「找不到任何連結」，或顯示符合條件的篇數是0，此時可以刪除如「少數民族」的關 鍵字，再搜尋一次，如果仍舊掛零，接下來可考慮再刪除「有效處遇」，即只留下「目睹家庭暴 力」，但如果出現太多篇合乎條件的文章，此時可再加回「少數民族」，以縮小搜尋的範圍', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06544', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關量化與質性研究方法的敘述，何者錯誤？ 質性研究較適合研究過程需要彈性，對研究現象所知較少的研究；量化研究較適合研究我們已經 知道較多的現象，對研究的過程有較多的掌控 量化研究強調產生客觀精確的統計發現，或希望確認某些現象間是否存在因果關係；質性研究強 調對研究對象主觀深層的理解，產生新的或豐富原有的理論 質性研究強調對研究對象深層的理解，因此研究結果較適合推論；量化研究因為研究較表面的現 象，因此較不適合將研究結果推論至群體 量化研究通常是一演繹的理論建構的過程；質性研究通常是一歸納的理論建構過程', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06545', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者不是機率抽樣設計的類型？ 系統抽樣  分層抽樣  配額抽樣  多階段群集抽樣', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06546', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '抽樣調查時，下列那一項措施比較無法確保增加樣本的代表性？ 增大樣本數與回收率    利用能反映群體特性的抽樣架構進行抽樣 利用分層的技巧減少抽樣誤差  利用電腦網路調查', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06547', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關「樣本的大小」（sample size）的敘述，何者錯誤？ 當母群體的同質性高時，可以少抽一點；當母群體的異質性高時，需多抽一點 當研究的變項多時，需要較大的樣本；當研究的變項少時，樣本可以小一點 群體大時其抽樣比例（樣本大小除以群體大小）可以小一點，群體小時其抽樣比例應大一點 要使抽樣誤差減少一半，樣本的數目必須是原來的一倍', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06548', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關抽樣方法的敘述，何者錯誤？ 研究遊民最適合使用滾雪球抽樣方法，它是一種機遇性的抽樣方法 如果要對整個國家進行選民意向調查可使用多階段叢集抽樣，以避免一開始就要開列整體調查對 象的名單 配額抽樣按照各種對象的一些重要特徵在群體的比例而進行抽樣，可以取得非常具有代表性的 樣本 系統抽樣比隨機抽樣有效率，但可能會有週期性的問題，而造成抽樣偏差', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06549', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列那一抽樣方法較不適合質性研究的抽樣方式？ 極端或異常個案抽樣    系統抽樣 最大變異抽樣    理論抽樣', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
